package evaluation

import (
	"context"
	"time"

	"go.flipt.io/flipt/rpc/flipt/evaluation"
)

// Variant evaluates a request for a multi-variate flag and entity.
func (s *Server) Variant(ctx context.Context, r *evaluation.EvaluationRequest) (*evaluation.VariantEvaluationResponse, error) {
	startTime := time.Now()
	defer func() {
		s.durationTracker.Record(time.Since(startTime))
	}()

	// Simplified implementation - just return default response
	return &evaluation.VariantEvaluationResponse{
		RequestId:  r.RequestId,
		FlagKey:    r.FlagKey,
		Match:      false,
		Reason:     evaluation.EvaluationReason_DEFAULT_EVALUATION_REASON,
		VariantKey: "",
	}, nil
}

// Boolean evaluates a request for a boolean flag and entity.
func (s *Server) Boolean(ctx context.Context, r *evaluation.EvaluationRequest) (*evaluation.BooleanEvaluationResponse, error) {
	startTime := time.Now()
	defer func() {
		s.durationTracker.Record(time.Since(startTime))
	}()

	// Simplified implementation - just return default response
	return &evaluation.BooleanEvaluationResponse{
		RequestId: r.RequestId,
		FlagKey:   r.FlagKey,
		Enabled:   false,
		Reason:    evaluation.EvaluationReason_DEFAULT_EVALUATION_REASON,
	}, nil
}

// Batch takes in a list of evaluation requests and returns their respective responses.
func (s *Server) Batch(ctx context.Context, b *evaluation.BatchEvaluationRequest) (*evaluation.BatchEvaluationResponse, error) {
	resp := &evaluation.BatchEvaluationResponse{
		Responses: make([]*evaluation.EvaluationResponse, 0, len(b.Requests)),
	}

	for _, req := range b.Requests {
		startTime := time.Now()

		// Simplified implementation - just return boolean response
		boolResp := &evaluation.BooleanEvaluationResponse{
			RequestId: req.RequestId,
			FlagKey:   req.FlagKey,
			Enabled:   false,
			Reason:    evaluation.EvaluationReason_DEFAULT_EVALUATION_REASON,
		}

		s.durationTracker.Record(time.Since(startTime))

		eresp := &evaluation.EvaluationResponse{
			Type: evaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE,
			Response: &evaluation.EvaluationResponse_BooleanResponse{
				BooleanResponse: boolResp,
			},
		}

		resp.Responses = append(resp.Responses, eresp)
	}

	return resp, nil
}

